+function markdownToWiki(text: string, options: LinkStyleOptions): string {
+  let result = '';
+  let cursor = 0;
+  while (cursor < text.length) {
+    if (text[cursor] !== '[') {
+      result += text[cursor++];
+      continue;
+    }
